      "sectionStatus": "done",
      "items": {
        "bullets": [
          "R-SWUI-001 的实现、基础浏览器矩阵和双布局 tarball 构建已交付，但审计发现原始目标态仍缺核心状态覆盖、完整 token/图表治理与 tarball 浏览器运行时证据。",
          "本 Feature 只补齐可在仓库内自动验证的目标态；私有 registry 凭据验证保持为明确的发布后续项。"
        ]
      }
    },
    "problem-statement": {
      "sectionStatus": "done",
      "items": {
        "coreProblem": "当前“已交付”门禁覆盖代表性路径，却不能证明 R-SWUI-001 要求的核心组件状态矩阵、主题 token 完整性、图表例外双主题审查和打包消费者真实运行时行为。",
        "nonGoals": [
          "不引入新的组件 API、AppShell、路由或产品页面布局。",
          "不在没有凭据时尝试真实私有 registry 发布。",
          "不重写历史 Feature/Step 的编号关系；该既有 numbering 校验问题单独记录。"
        ]
      }
    },
    "context-constraints": {
      "sectionStatus": "done",
      "items": {
        "researchSource": "docs/research/R-SWUI-001-theme-consistency-governance-research.md §7、§8",
        "currentEvidence": "2026-07-16 本地重跑：静态契约、类型检查、示例构建、Playwright（18 passed / 6 scope-specific skips）和 isolated/hoisted tarball 构建均通过；publish:dry 因 npm.inet.swqt.net 未登录受阻。",
        "projectConstraints": [
          "@swui/ui 只能使用语义 token，不新增产品壳层。",
          "浏览器基线必须使用 Playwright Chromium，并固定主题、视口与稳定夹具。",
          "所有新门禁须可在本地和 .github/workflows/quality.yml 中复用。"
        ],
        "axisPositioning": "required: application=sdk-design-system; technology=React+Tailwind+Playwright+Bun; validation=browser+a11y+static+packed-consumer; externalDependency=private-registry-credentials.",
        "axisSplitSignals": "组件状态、token/图表契约与发布态运行时分别有独立失败根因、夹具和验收；保留为单一 Feature 以共同关闭同一研究报告目标态。",
        "axisSnapshot": "单 Feature、三 Step；共享来源为 R-SWUI-001，独立 review 价值来自浏览器状态、静态主题治理和 pack 后运行时。"
      }
    },
