            "id": "C",
            "name": "仅更新报告状态，不新增门禁",
            "technical": "无法消除已审计的测试和治理缺口。",
            "economic": "短期成本最低，但质量债保留。",
            "legal": "无额外影响。",
            "operational": "无法防止回归。",
            "schedule": "最快但不达标。"
          }
        ],
        "recommended": "B",
        "conclusion": "ProceedWithScopeCut：先完成可重复本地目标态，远端 registry 验证保持为有界外部后续项。"
      }
    },
    "decision-summary": {
      "sectionStatus": "done",
      "items": {
        "changePosture": "migrate-forward",
        "changePostureSource": "user-confirmed",
        "proposedDecision": "采用 Option B，按自然聚合簇设计三个 Step；用户本轮授权创建 Feature，不视为进入 design/auto 的确认。",
        "observableSuccess": "任一核心组件状态、主题 token、图表例外或 tarball 运行时回归都会由本地和 CI 的相应门禁失败捕获。",
        "testabilityRisks": "registry 登录、真实远端发布和某些图表的视觉语义需要外部凭据或受控人工审查；它们必须有显式证据而非静默跳过。",
        "primaryIntegrationSurface": "从已打包 @swui/ui 安装的消费者在真实 Playwright 浏览器中切换主题并呈现核心状态夹具。",
        "firstDemonstrableSlice": "先让 Button/Input/Select/图标按钮的状态夹具在双主题四视口下截图和 axe 均通过，并生成覆盖清单。",
        "tracerScan": "T-hit=T1,T5; N-hit=none; weak>=2=No"
      }
    },
    "acceptance-criteria": {
      "sectionStatus": "done",
      "items": {
        "criteria": [
          "核心 Button、Input、Select、图标按钮和 ThemeControl 的适用 default/hover/focus-visible/disabled/loading/error/empty/selected 状态在 light/dark × compact/data-dense/lg/xl 具有可追溯视觉与 axe 证据；例外有统计和理由。",
          "静态 token 门禁解析两套正式主题的必填语义 token、引用/循环/弃用关系和前景背景配对；裸色/裸尺寸扫描覆盖已定义语法边界。",
          "图表 allowlist 每项都有语义映射、双主题渲染/对比度证据及人工审查记录。",
          "nested 与 hoisted tarball 消费者均在真实浏览器中验证组件渲染、主题切换和 tokens.css/@source 生效。",
          "R-SWUI-001 标注为历史研究范围并链接到交付 Feature 与遗留外部验证；项目 docs 可从 README 发现。"
        ],
